        "fields": {
          "id": "string",
          "label": "string",
          "done": "boolean",
          "note": "string",
          "clockedAt": "number (ms epoch, 0 = not clocked)"
        },
        "persistence": "session-scoped (durable only while session open)"
      },
      "PatrolSession": {
        "fields": {
          "id": "string",
          "status": "PatrolStatus",
          "startedAt": "number (ms epoch)",
          "endedAt": "number (ms epoch, 0 = ongoing)",
          "checkpoints": "PatrolCheckpoint[]"
        },
        "persistence": "durable (Preferences JSON) — at most one active session"
      },
      "Contact": {
        "fields": {
          "id": "string",
          "name": "string",
          "role": "string",
          "phone": "string"
        },
        "persistence": "durable (Preferences JSON)"
      }
    },
    "enums": {
      "RecordCategory": "general | equipment | environment | behavior | fire | other",
      "RiskSeverity": "low | medium | high",
      "FixStatus": "pending | progress | resolved",
      "PatrolStatus": "idle | active | completed"
    },
    "computed": {
      "summary.urgentCount": "count of risks where severity=high and fixStatus!=resolved",
      "summary.pendingCount": "count of risks where fixStatus=pending + records created today that are open context",
      "summary.completedTodayCount": "count of risks resolved today + checkpoints clocked today + patrol sessions completed today",
      "tracking.overdue": "risks where fixStatus!=resolved and dueAt>0 and dueAt<now",
      "stats.completionRate": "resolved / total risks (0 when total=0)",
      "stats.resolvedThisWeek": "risks resolved in last 7 days",
      "stats.chartData": "counts by category/status bucket for the selected range/category"
    },
    "settingsForm": {
      "recordForm": "title, category, note, photoUri (edit-in-place when editing)",
      "riskForm": "title, location, severity, description, photoUri (edit-in-place when editing)",
      "contactForm": "name, role, phone (edit-in-place when editing)",
      "checkpointNote": "note text for one checkpoint",
      "filter": "{ status: FixStatus[], category: RecordCategory[] }"
    }
  },
  "services": {
    "StorageService": {
      "boundary": "Preferences wrapper (data-preferences) keyed 'pinankou_store'. Serializes per-collection JSON. Async init + get/set.",
      "keys": ["records", "risks", "patrol", "contacts"],
      "fallback": "in-memory cache when preferences unavailable"
    },
    "DataService": {
      "boundary": "domain repositories + derived queries (summary, tracking, stats). Single in-memory source of truth mirrored to StorageService.",
      "methods": "loadAll, getRecords/queryRecords, saveRecord/deleteRecord, getRisks/queryRisks, saveRisk/deleteRisk/advanceRisk, patrol start/addCheckpoint/toggleCheckpoint/saveCheckpointNote/endPatrol, contacts CRUD, tracking list, stats compute"
    },
    "DialAdapter": {
      "boundary": "system call intent via want constant (ohos.want.action.dial) with tel: phone; graceful no-op feedback when unavailable",
      "notes": "stub-safe; only triggered by call-contact event"
    },
    "PhotoAdapter": {
      "boundary": "local file URI capture stub; returns empty URI in headless/no-camera context",
      "notes": "evidence capture is local only; stub returns '' until wired"
    }
  },
  "stateMachine": {
    "root": {
      "states": ["idle", "ready", "loading"],
      "initial": "idle",
      "transitions": "idle --load--> loading --ready--> ready"
    },
    "sheet": {
      "states": ["none", "record-form", "risk-form", "contact-form", "checkpoint-note", "filter"],
      "initial": "none",
      "transitions": [
        "none --open-add-record-sheet--> record-form",
        "none --open-add-risk-sheet--> risk-form",
        "none --open-add-contact-sheet--> contact-form",
        "none --open-checkpoint-note--> checkpoint-note",
        "none --open-filter-sheet--> filter",
        "* --save/cancel/close--> none"
      ]
    },
    "patrol": {
      "states": ["idle", "active", "completed"],
      "transitions": [
        "idle --start-patrol-session--> active",
        "active --end-patrol-session--> completed",
        "completed --start-patrol-session--> active (new session)"
      ]
    },
    "fixStatus (per risk)": {
      "transitions": "pending --advance--> progress --advance--> resolved --advance--> resolved (idempotent)"
    },
    "filter": {
      "states": "active filter object {status[], category[]}; reset returns to empty (show all)"
    }
  },
  "interactionFlows": [
    {
      "name": "save-record",
      "trigger": "record-form-save-button",
      "inputs": ["/recordForm/title", "/recordForm/category", "/recordForm/note", "photoUri"],
      "validation": "title non-empty (trim); category in enum; note optional",
      "steps": ["validate", "upsert SafetyRecord (create or edit)", "persist", "refresh records + summary", "close sheet"],
      "errorPath": "invalid title -> keep sheet open, mark record-form-error"
    },
    {
      "name": "save-risk",
      "trigger": "risk-form-save-button",
      "inputs": ["/riskForm/title", "/riskForm/location", "/riskForm/severity", "/riskForm/description", "photoUri"],
      "validation": "title non-empty; severity in enum; dueAt default derived from severity (high=1d, medium=3d, low=7d)",
      "steps": ["validate", "upsert RiskHazard (fixStatus pending on create, preserved on edit)", "persist", "refresh risks + tracking + summary", "close sheet"],
      "errorPath": "invalid title -> keep sheet open, mark risk-form-error"
    },
    {
      "name": "save-contact",
      "trigger": "contact-form-save-button",
      "inputs": ["/contactForm/name", "/contactForm/role", "/contactForm/phone"],
      "validation": "name non-empty; phone non-empty",
      "steps": ["validate", "upsert Contact", "persist", "refresh contacts", "close sheet"],
      "errorPath": "invalid name/phone -> keep sheet open, mark contact-form-error"
    },
    {
      "name": "start-patrol-session",
      "trigger": "patrol-start-button | home-start-patrol-button",
      "steps": ["create PatrolSession status=active startedAt=now", "seed zero checkpoints (user adds on the fly)", "persist", "switch surface to patrol"],
      "expectedState": "/patrol/sessionStatus == 'active'"
    },
    {
      "name": "add-checkpoint",
      "trigger": "patrol-add-checkpoint-button",
      "steps": ["append PatrolCheckpoint label='检查点 N' done=false", "persist"]
    },
    {
      "name": "toggle-checkpoint",
      "trigger": "patrol-checkpoint-{id}-toggle",
      "context": "checkpointId",
      "steps": ["flip done", "set clockedAt=now when done else 0", "persist"]
    },
    {
      "name": "save-checkpoint-note",
      "trigger": "checkpoint-note-save-button",
      "context": "checkpointId",
      "steps": ["set checkpoint.note", "persist", "close sheet"]
    },
    {
      "name": "end-patrol-session",
      "trigger": "patrol-end-button",
      "steps": ["set status=completed endedAt=now", "persist", "refresh summary completedTodayCount"]
    },
    {
      "name": "call-contact",
      "trigger": "contacts-item-{id}-call-button",
      "context": "contactId",
      "steps": ["resolve phone", "DialAdapter.startCall(phone)"],
      "errorPath": "dial unavailable -> user-visible feedback message"
    },
    {
      "name": "delete-contact",
      "trigger": "contacts-item-{id}-delete-button",
      "context": "contactId",
      "steps": ["confirm", "remove Contact", "persist", "refresh contacts"]
    },
    {
      "name": "advance-fix-status",
      "trigger": "tracking-item-{id}-advance-button",
      "context": "trackingItemId",
      "steps": ["pending->progress->resolved", "persist", "refresh tracking + summary + stats"]
    },
    {
      "name": "filter-tracking-status",
      "trigger": "tracking-filter-*",
      "context": "status",
      "steps": ["set tracking status filter to single status (toggle)", "recompute tracking list"]
    },
    {
      "name": "apply-filter",
      "trigger": "filter-apply-button",
      "steps": ["apply {status[], category[]} to current list surface (records or risks)", "close filter sheet"]
    },
    {
      "name": "reset-filter",
      "trigger": "filter-reset-button",
      "steps": ["clear filter", "close filter sheet"]
    },
    {
      "name": "export-stats",
      "trigger": "stats-export-button",
      "steps": ["compute current stats snapshot", "surface export feedback (local summary string)"],
      "notes": "no cloud; export is a local snapshot string"
    }
  ],
  "testTargets": [
    "home-urgent-count",
    "home-pending-count",
    "home-completed-today-count",
    "home-recent-list",
    "records-list",
    "risks-list",
    "patrol-checkpoint-list",
    "patrol-session-status",
    "contacts-list",
    "tracking-list",
    "stats-total-records",
    "stats-open-risks",
    "stats-resolved-this-week",
    "stats-completion-rate"
  ],
  "changeRequests": [
    {
      "issue": "ui-tree tracking tab id is 'tab-tracking' but navigation model lists 5 tabs: 首页/事项/巡检/进度/看板. Contacts surface (tabId null) is reached from home action navigate-contacts.",
      "resolution": "Keep tab ids tab-home, tab-records, tab-patrol, tab-tracking, tab-stats. Risks reached via records surface filter or home quick action; contacts via home action. This matches ui-tree surfaces (risks-page has tabId tab-risks — see below)."
    },
    {
      "issue": "ui-tree assigns tabId 'tab-risks' to risks-page but spec's 5-tab model is 首页/事项/巡检/进度/看板 (no dedicated risks tab).",
      "resolution": "Honor ui-tree tab ids as the semantic source of truth: tab-home, tab-records, tab-risks, tab-patrol, tab-tracking, tab-stats. Bottom bar shows the 5 primary tabs (home/records/patrol/tracking/stats); risks surface is reachable from home quick action and via records-context. Verify against final HTML during visual integration."
    }
  ],
  "openQuestions": [
    "patrol checkpoints created on the fly (default) — confirmed in spec open questions",
    "resolved items shown with status filter (default show all)"
  ]
}

