  count: number;
}

export interface HomeSummary {
  urgentCount: number;
  pendingCount: number;
  completedTodayCount: number;
  recentItems: HomeRecentItem[];
}

export interface HomeRecentItem {
  id: string;
  kind: 'record' | 'risk' | 'patrol' | 'contact';
  title: string;
  subtitle: string;
  timestamp: number;
}

export const RECORD_CATEGORY_LABELS: Record<RecordCategory, string> = {
  'general': '综合',
  'equipment': '设备',
  'environment': '环境',
  'behavior': '行为',
  'fire': '消防',
  'other': '其他',
};

export const RECORD_CATEGORY_LIST: RecordCategory[] = [
  'general',
  'equipment',
  'environment',
  'behavior',
  'fire',
  'other',
];

export const RISK_SEVERITY_LABELS: Record<RiskSeverity, string> = {
  'low': '低',
  'medium': '中',
  'high': '高',
};

export const RISK_SEVERITY_LIST: RiskSeverity[] = ['low', 'medium', 'high'];

export const FIX_STATUS_LABELS: Record<FixStatus, string> = {
  'pending': '待处理',
  'progress': '整改中',
  'resolved': '已闭环',
};

export const FIX_STATUS_LIST: FixStatus[] = ['pending', 'progress', 'resolved'];

export const STATS_RANGE_LABELS: Record<StatsRange, string> = {
  'week': '近7天',
  'month': '近30天',
  'all': '全部',
};

export const STATS_RANGE_LIST: StatsRange[] = ['week', 'month', 'all'];

// Default remediation window (ms) per severity when creating a risk.
export const SEVERITY_DUE_MS: Record<RiskSeverity, number> = {
  'low': 7 * 24 * 60 * 60 * 1000,
  'medium': 3 * 24 * 60 * 60 * 1000,
  'high': 24 * 60 * 60 * 1000,
};

export function nextFixStatus(current: FixStatus): FixStatus {
  if (current === 'pending') {
    return 'progress';
  }
  if (current === 'progress') {
    return 'resolved';
  }
  return 'resolved';
}

export function emptyRecordFilter(): RecordFilter {
  return { query: '', statuses: [], categories: [] } as RecordFilter;
}

export function emptyRiskFilter(): RiskFilter {
  return { query: '', severities: [], statuses: [] } as RiskFilter;
}

export function emptyTrackingFilter(): TrackingFilter {
  return { statuses: [], onlyOverdue: false } as TrackingFilter;
}

export function isSameDay(a: number, b: number): boolean {
  if (a <= 0 || b <= 0) {
    return false;
  }
  const day = 24 * 60 * 60 * 1000;
  const da = Math.floor(a / day);
  const db = Math.floor(b / day);
  return da === db;
}

export function withinLastDays(now: number, ts: number, days: number): boolean {
  if (ts <= 0) {
    return false;
  }
  return ts >= now - days * 24 * 60 * 60 * 1000 && ts <= now;
}

