// Offline-first preferences wrapper for 平安扣 Pinankou.
// Headless-safe: works in-memory before a context is attached, mirrors to
// data-preferences once initialized. Serializes whole collections as JSON strings.

import { preferences } from '@kit.ArkData';
import { common } from '@kit.AbilityKit';
import { hilog } from '@kit.PerformanceAnalysisKit';

const DOMAIN = 0x0910;
const STORE_NAME = 'pinankou_store';

type Listener = () => void;

export class StorageService {
  private store: preferences.Preferences | null = null;
  private cache: Map<string, string> = new Map<string, string>();
  private listeners: Set<Listener> = new Set<Listener>();

  async init(context: common.Context): Promise<void> {
    try {
      this.store = await preferences.getPreferences(context, STORE_NAME);
      // Prime the in-memory cache with known collection keys.
      const keys: string[] = ['records', 'risks', 'patrol', 'contacts'];
      for (const key of keys) {
        const raw = await this.store.get(key, '');
        if (typeof raw === 'string' && raw.length > 0) {
          this.cache.set(key, raw);
        }
      }
    } catch (err) {
      hilog.error(DOMAIN, 'pinankou.storage', 'init failed: %{public}s', JSON.stringify(err));
      this.store = null;
    }
  }

  async read(key: string): Promise<string> {
    const cached = this.cache.get(key);
    if (cached !== undefined) {
      return cached;
    }
    if (this.store) {
      try {
        const raw = await this.store.get(key, '');
        if (typeof raw === 'string') {
          this.cache.set(key, raw);
          return raw;
        }
      } catch (err) {
        hilog.error(DOMAIN, 'pinankou.storage', 'read %{public}s failed: %{public}s', key, JSON.stringify(err));
      }
    }
    return '';
  }

  async write(key: string, value: string): Promise<void> {
    this.cache.set(key, value);
    if (this.store) {
      try {
        await this.store.put(key, value);
        await this.store.flush();
      } catch (err) {
        hilog.error(DOMAIN, 'pinankou.storage', 'write %{public}s failed: %{public}s', key, JSON.stringify(err));
      }
    }
    this.emit();
  }

  onChange(listener: Listener): () => void {
    this.listeners.add(listener);
    return () => {
      this.listeners.delete(listener);
    };
  }

  private emit(): void {
    this.listeners.forEach((l: Listener) => {
      try {
        l();
      } catch (err) {
        hilog.error(DOMAIN, 'pinankou.storage', 'listener error: %{public}s', JSON.stringify(err));
      }
    });
  }
}

export const storage: StorageService = new StorageService();

