input.content:
// Domain repository + derived queries for 平安扣 Pinankou.
// In-memory source of truth, mirrored to StorageService. Headless-logic only.

import { storage } from './StorageService';
import {
  SafetyRecord,
  RiskHazard,
  PatrolSession,
  PatrolCheckpoint,
  Contact,
  RecordFilter,
  RiskFilter,
  TrackingFilter,
  StatsSnapshot,
  StatsRange,
  RecordCategory,
  HomeSummary,
  HomeRecentItem,
  FIX_STATUS_LIST,
  RECORD_CATEGORY_LIST,
  SEVERITY_DUE_MS,
  nextFixStatus,
  emptyRecordFilter,
  emptyRiskFilter,
  emptyTrackingFilter,
  isSameDay,
  withinLastDays,
  RiskSeverity,
  FixStatus,
} from '../model/Types';

const EMPTY_RECORDS: SafetyRecord[] = [];
const EMPTY_RISKS: RiskHazard[] = [];
const EMPTY_CONTACTS: Contact[] = [];
const EMPTY_CHECKPOINTS: PatrolCheckpoint[] = [];

export class DataService {
  private records: SafetyRecord[] = [];
  private risks: RiskHazard[] = [];
  private patrol: PatrolSession | null = null;
  private contacts: Contact[] = [];
  private loaded: boolean = false;
  private idCounter: number = 1;

  async loadAll(): Promise<void> {
    if (this.loaded) {
      return;
    }
    const recordsRaw = await storage.read('records');
    const risksRaw = await storage.read('risks');
    const patrolRaw = await storage.read('patrol');
    const contactsRaw = await storage.read('contacts');

    this.records = this.parseRecords(recordsRaw);
    this.risks = this.parseRisks(risksRaw);
    this.patrol = this.parsePatrol(patrolRaw);
    this.contacts = this.parseContacts(contactsRaw);
    this.bumpIdSeed();
    this.loaded = true;
  }

  isLoaded(): boolean {
    return this.loaded;
  }

  // ---- id helper ----
  private nextId(prefix: string): string {
    const stamp = Date.now();
    const id = `${prefix}_${stamp}_${this.idCounter}`;
    this.idCounter += 1;
    return id;
  }

  private bumpIdSeed(): void {
    const all: number[] = [];
    const collect = (id: string) => {
      const parts = id.split('_');
      const last = parts[parts.length - 1];
      const n = Number.parseInt(last, 10);
      if (!Number.isNaN(n)) {
        all.push(n);
      }
    };
    this.records.forEach((r: SafetyRecord) => collect(r.id));
    this.risks.forEach((r: RiskHazard) => collect(r.id));
    this.contacts.forEach((c: Contact) => collect(c.id));
    this.idCounter = all.length > 0 ? Math.max(...all) + 1 : 1;
  }

  // ---- Records ----
  getRecords(filter: RecordFilter): SafetyRecord[] {
    const f = filter || emptyRecordFilter();
    const query = f.query.trim().toLowerCase();
    let out: SafetyRecord[] = [];
    for (const r of this.records) {
      if (query.length > 0 && !this.recordMatches(r, query)) {
        continue;
      }
      out.push(r);
    }
    out.sort((a: SafetyRecord, b: SafetyRecord) => b.updatedAt - a.updatedAt);
    return out;
  }

  private recordMatches(r: SafetyRecord, query: string): boolean {
    if (r.title.toLowerCase().indexOf(query) >= 0) {
      return true;
    }
    if (r.note.toLowerCase().indexOf(query) >= 0) {
      return true;
    }
    return false;
  }

  saveRecord(input: SafetyRecord): SafetyRecord {
    const now = Date.now();
    if (input.id.length === 0) {
      const created: SafetyRecord = {
        id: this.nextId('rec'),
        title: input.title,
        category: input.category,
        note: input.note,
        photoUri: input.photoUri,
        createdAt: now,
        updatedAt: now,
      };
      this.records.push(created);
      this.persistRecords();
      return created;
    }
    for (let i = 0; i < this.records.length; i++) {
      if (this.records[i].id === input.id) {
        const merged: SafetyRecord = {
          id: this.records[i].id,
          title: input.title,
          category: input.category,
          note: input.note,
          photoUri: input.photoUri,
          createdAt: this.records[i].createdAt,
          updatedAt: now,
        };
        this.records[i] = merged;
        this.persistRecords();
        return merged;
      }
    }
    return input;
  }

  deleteRecord(id: string): void {
    this.records = this.records.filter((r: SafetyRecord) => r.id !== id);
    this.persistRecords();
  }

  // ---- Risks ----
  getRisks(filter: RiskFilter): RiskHazard[] {
    const f = filter || emptyRiskFilter();
    const query = f.query.trim().toLowerCase();
    let out: RiskHazard[] = [];
    for (const r of this.risks) {
      if (query.length > 0 && !this.riskMatches(r, query)) {
        continue;
      }
      out.push(r);
    }
    out.sort((a: RiskHazard, b: RiskHazard) => b.updatedAt - a.updatedAt);
    return out;
  }

  private riskMatches(r: RiskHazard, query: string): boolean {
    if (r.title.toLowerCase().indexOf(query) >= 0) {
      return true;
    }
    if (r.location.toLowerCase().indexOf(query) >= 0) {
      return true;
    }
    if (r.description.toLowerCase().indexOf(query) >= 0) {
      return true;
    }
    return false;
  }

  saveRisk(input: RiskHazard): RiskHazard {
    const now = Date.now();
    const dueAt = input.dueAt > 0 ? input.dueAt : now + SEVERITY_DUE_MS[input.severity];
    if (input.id.length === 0) {
      const created: RiskHazard = {
        id: this.nextId('risk'),
        title: input.title,
        location: input.location,
        severity: input.severity,
        description: input.description,
        photoUri: input.photoUri,
        fixStatus: 'pending',
        dueAt: dueAt,
        createdAt: now,
        updatedAt: now,
      };
      this.risks.push(created);
      this.persistRisks();
      return created;
    }
    for (let i = 0; i < this.risks.length; i++) {
      if (this.risks[i].id === input.id) {
        const merged: RiskHazard = {
          id: this.risks[i].id,
          title: input.title,
          location: input.location,
          severity: input.severity,
          description: input.description,
          photoUri: input.photoUri,
          fixStatus: this.risks[i].fixStatus,
          dueAt: dueAt,
          createdAt: this.risks[i].createdAt,
          updatedAt: now,
        };
        this.risks[i] = merged;
        this.persistRisks();
        return merged;
      }
    }
    return input;
  }

  deleteRisk(id: string): void {
    this.risks = this.risks.filter((r: RiskHazard) => r.id !== id);
    this.persistRisks();
  }

  advanceRisk(id: string): RiskHazard | null {
    for (let i = 0; i < this.risks.length; i++) {
      if (this.risks[i].id === id) {
        const updated: RiskHazard = {
          id: this.risks[i].id,
          title: this.risks[i].title,
          location: this.risks[i].location,
          severity: this.risks[i].severity,
          description: this.risks[i].description,
          photoUri: this.risks[i].photoUri,
          fixStatus: nextFixStatus(this.risks[i].fixStatus),
          dueAt: this.risks[i].dueAt,
          createdAt: this.risks[i].createdAt,
          updatedAt: Date.now(),
        };
        this.risks[i] = updated;
        this.persistRisks();
        return updated;
      }
    }
    return null;
  }

  isRiskOverdue(r: RiskHazard, now: number): boolean {
    return r.fixStatus !== 'resolved' && r.dueAt > 0 && r.dueAt < now;
  }

  // ---- Tracking (derived from risks) ----
  getTrackingItems(filter: TrackingFilter): RiskHazard[] {
    const f = filter || emptyTrackingFilter();
    const now = Date.now();
    let out: RiskHazard[] = [];
    for (const r of this.risks) {
      if (f.onlyOverdue && !this.isRiskOverdue(r, now)) {
        continue;
      }
      if (f.statuses.length > 0 && f.statuses.indexOf(r.fixStatus) < 0) {
        continue;
      }
      out.push(r);
    }
    out.sort((a: RiskHazard, b: RiskHazard) => a.dueAt - b.dueAt);
    return out;
  }

  countOverdue(): number {
    const now = Date.now();
    let n = 0;
    for (const r of this.risks) {
      if (this.isRiskOverdue(r, now)) {
        n += 1;
      }
    }
    return n;
  }

  // ---- Patrol ----
  getPatrol(): PatrolSession | null {
    return this.patrol;
  }

  startPatrol(): PatrolSession {
    const session: PatrolSession = {
      id: this.nextId('patrol'),
      status: 'active',
      startedAt: Date.now(),
      endedAt: 0,
      checkpoints: [],
    };
    this.patrol = session;
    this.persistPatrol();
    return session;
  }

  endPatrol(): PatrolSession | null {
    if (!this.patrol) {
      return null;
    }
    const ended: PatrolSession = {
      id: this.patrol.id,
      status: 'completed',
      startedAt: this.patrol.startedAt,
      endedAt: Date.now(),
      checkpoints: this.patrol.checkpoints,
    };
    this.patrol = ended;
    this.persistPatrol();
    return ended;
  }

  addCheckpoint(label?: string): PatrolCheckpoint | null {
    if (!this.patrol || this.patrol.status !== 'active') {
      return null;
    }
    const index = this.patrol.checkpoints.length + 1;
    const checkpoint: PatrolCheckpoint = {
      id: this.nextId('cp'),
      label: (label && label.length > 0) ? label : `检查点 ${index}`,
      done: false,
      note: '',
      clockedAt: 0,
    };
    this.patrol.checkpoints.push(checkpoint);
    this.persistPatrol();
    return checkpoint;
  }

  toggleCheckpoint(checkpointId: string): PatrolCheckpoint | null {
    if (!this.patrol) {
      return null;
    }
    for (let i = 0; i < this.patrol.checkpoints.length; i++) {
      const cp = this.patrol.checkpoints[i];
      if (cp.id === checkpointId) {
        const nextDone = !cp.done;
        const updated: PatrolCheckpoint = {
          id: cp.id,
          label: cp.label,
          done: nextDone,
          note: cp.note,
          clockedAt: nextDone ? Date.now() : 0,
        };
        this.patrol.checkpoints[i] = updated;
        this.persistPatrol();
        return updated;
      }
    }
    return null;
  }

  saveCheckpointNote(checkpointId: string, note: string): PatrolCheckpoint | null {
    if (!this.patrol) {
      return null;
    }
    for (let i = 0; i < this.patrol.checkpoints.length; i++) {
      const cp = this.patrol.checkpoints[i];
      if (cp.id === checkpointId) {
        const updated: PatrolCheckpoint = {
          id: cp.id,
          label: cp.label,
          done: cp.done,
          note: note,
          clockedAt: cp.clockedAt,
        };
        this.patrol.checkpoints[i] = updated;
        this.persistPatrol();
        return updated;
      }
    }
    return null;
  }

  // ---- Contacts ----
  getContacts(): Contact[] {
    const out: Contact[] = [];
    for (const c of this.contacts) {
      out.push(c);
    }
    out.sort((a: Contact, b: Contact) => a.name.localeCompare(b.name));
    return out;
  }

  saveContact(input: Contact): Contact {
    if (input.id.length === 0) {
      const created: Contact = {
        id: this.nextId('ct'),
        name: input.name,
        role: input.role,
        phone: input.phone,
      };
      this.contacts.push(created);
      this.persistContacts();
      return created;
    }
    for (let i = 0; i < this.contacts.length; i++) {
      if (this.contacts[i].id === input.id) {
        const merged: Contact = {
          id: this.contacts[i].id,
          name: input.name,
          role: input.role,
          phone: input.phone,
        };
        this.contacts[i] = merged;
        this.persistContacts();
        return merged;
      }
    }
    return input;
  }

  deleteContact(id: string): void {
    this.contacts = this.contacts.filter((c: Contact) => c.id !== id);
    this.persistContacts();
  }

  // ---- Derived: home summary ----
  computeHomeSummary(): HomeSummary {
    const now = Date.now();
    let urgent = 0;
    let pendingRisks = 0;
    for (const r of this.risks) {
      if (r.severity === 'high' && r.fixStatus !== 'resolved') {
        urgent += 1;
      }
      if (r.fixStatus === 'pending') {
        pendingRisks += 1;
      }
    }
    const completedToday = this.completedTodayCount(now);
    const recent = this.recentItems(now);
    return {
      urgentCount: urgent,
      pendingCount: pendingRisks,
      completedTodayCount: completedToday,
      recentItems: recent,
    } as HomeSummary;
  }

  private completedTodayCount(now: number): number {
    let n = 0;
    for (const r of this.risks) {
      if (r.fixStatus === 'resolved' && isSameDay(r.updatedAt, now)) {
        n += 1;
      }
    }
    if (this.patrol && this.patrol.status === 'completed' && isSameDay(this.patrol.endedAt, now)) {
      n += 1;
    }
    return n;
  }

  private recentItems(now: number): HomeRecentItem[] {
    const items: HomeRecentItem[] = [];
    for (const r of this.records) {
      items.push({
        id: r.id,
        kind: 'record',
        title: r.title,
        subtitle: r.note,
        timestamp: r.updatedAt,
      } as HomeRecentItem);
    }
    for (const r of this.risks) {
      items.push({
        id: r.id,
        kind: 'risk',
        title: r.title,
        subtitle: r.location,
        timestamp: r.updatedAt,
      } as HomeRecentItem);
    }
    if (this.patrol) {
      items.push({
        id: this.patrol.id,
        kind: 'patrol',
        title: '巡检会话',
        subtitle: `检查点 ${this.patrol.checkpoints.length}`,
        timestamp: this.patrol.startedAt,
      } as HomeRecentItem);
    }
    items.sort((a: HomeRecentItem, b: HomeRecentItem) => b.timestamp - a.timestamp);
    return items.slice(0, 5);
  }

  // ---- Derived: stats ----
  computeStats(range: StatsRange, category: RecordCategory | 'all'): StatsSnapshot {
    const now = Date.now();
    const days = range === 'week' ? 7 : range === 'month' ? 30 : 99999;

    let totalRecords = 0;
    for (const r of this.records) {
      if (withinLastDays(now, r.createdAt, days) && (category === 'all' || r.category === category)) {
        totalRecords += 1;
      }
    }

    let openRisks = 0;
    let resolvedThisWeek = 0;
    let totalRisks = 0;
    for (const r of this.risks) {
      if (category !== 'all' && !this.riskMatchesCategory(r, category)) {
        continue;
      }
      if (withinLastDays(now, r.createdAt, days)) {
        totalRisks += 1;
      }
      if (r.fixStatus !== 'resolved' && withinLastDays(now, r.createdAt, days)) {
        openRisks += 1;
      }
      if (r.fixStatus === 'resolved' && withinLastDays(now, r.updatedAt, 7)) {
        resolvedThisWeek += 1;
      }
    }

    const completionRate = totalRisks > 0
      ? Math.round((this.countResolvedRisks(category) / this.totalRisksAll(category)) * 100)
      : 0;

    const byCategory = this.countByCategory(days, now);
    const byStatus = this.countByStatus(category);

    return {
      range: range,
      category: category,
      totalRecords: totalRecords,
      openRisks: openRisks,
      resolvedThisWeek: resolvedThisWeek,
      completionRate: completionRate,
      chartData: { byCategory: byCategory, byStatus: byStatus } as StatsChart,
    } as StatsSnapshot;
  }

  private riskMatchesCategory(r: RiskHazard, category: RecordCategory): boolean {
    // Risks have no category field; treat equipment/fire heuristically via description keywords.
    const text = `${r.title} ${r.description}`.toLowerCase();
    if (category === 'equipment') {
      return text.indexOf('设备') >= 0 || text.indexOf('equipment') >= 0;
    }
    if (category === 'fire') {
      return text.indexOf('消防') >= 0 || text.indexOf('fire') >= 0;
    }
    if (category === 'environment') {
      return text.indexOf('环境') >= 0 || text.indexOf('environment') >= 0;
    }
    return false;
  }

  private countResolvedRisks(category: RecordCategory | 'all'): number {
    let n = 0;
    for (const r of this.risks) {
      if (r.fixStatus !== 'resolved') {
        continue;
      }
      if (category !== 'all' && !this.riskMatchesCategory(r, category)) {
        continue;
      }
      n += 1;
    }
    return n;
  }

  private totalRisksAll(category: RecordCategory | 'all'): number {
    let n = 0;
    for (const r of this.risks) {
      if (category !== 'all' && !this.riskMatchesCategory(r, category)) {
        continue;
      }
      n += 1;
    }
    return n;
  }

  private countByCategory(days: number, now: number): CategoryCount[] {
    const out: CategoryCount[] = [];
    for (const cat of RECORD_CATEGORY_LIST) {
      let count = 0;
      for (const r of this.records) {
        if (r.category === cat && withinLastDays(now, r.createdAt, days)) {
          count += 1;
        }
      }
      out.push({ category: cat, count: count } as CategoryCount);
    }
    return out;
  }

  private countByStatus(category: RecordCategory | 'all'): StatusCount[] {
    const out: StatusCount[] = [];
    for (const status of FIX_STATUS_LIST) {
      let count = 0;
      for (const r of this.risks) {
        if (r.fixStatus === status && (category === 'all' || this.riskMatchesCategory(r, category))) {
          count += 1;
        }
      }
      out.push({ status: status, count: count } as StatusCount);
    }
    return out;
  }

  // ---- persistence mirrors ----
  private persistRecords(): void {
    storage.write('records', JSON.stringify(this.records));
  }

  private persistRisks(): void {
    storage.write('risks', JSON.stringify(this.risks));
  }

  private persistPatrol(): void {
    const raw = this.patrol ? JSON.stringify(this.patrol) : '';
    storage.write('patrol', raw);
  }

  private persistContacts(): void {
    storage.write('contacts', JSON.stringify(this.contacts));
  }

  // ---- parse helpers ----
  private parseRecords(raw: string): SafetyRecord[] {
    if (raw.length === 0) {
      return EMPTY_RECORDS.slice();
    }
    try {
      const parsed = JSON.parse(raw) as SafetyRecord[];
      return Array.isArray(parsed) ? parsed : EMPTY_RECORDS.slice();
    } catch (err) {
      return EMPTY_RECORDS.slice();
    }
  }

  private parseRisks(raw: string): RiskHazard[] {
    if (raw.length === 0) {
      return EMPTY_RISKS.slice();
    }
    try {
      const parsed = JSON.parse(raw) as RiskHazard[];
      return Array.isArray(parsed) ? parsed : EMPTY_RISKS.slice();
    } catch (err) {
      return EMPTY_RISKS.slice();
    }
  }

  private parsePatrol(raw: string): PatrolSession | null {
    if (raw.length === 0) {
      return null;
    }
    try {
      const parsed = JSON.parse(raw) as PatrolSession;
      if (parsed && typeof parsed.id === 'string') {
        if (!Array.isArray(parsed.checkpoints)) {
          parsed.checkpoints = EMPTY_CHECKPOINTS.slice();
        }
        return parsed;
      }
      return null;
    } catch (err) {
      return null;
    }
  }

  private parseContacts(raw: string): Contact[] {
    if (raw.length === 0) {
      return EMPTY_CONTACTS.slice();
    }
    try {
      const parsed = JSON.parse(raw) as Contact[];
      return Array.isArray(parsed) ? parsed : EMPTY_CONTACTS.slice();
    } catch (err) {
      return EMPTY_CONTACTS.slice();
    }
  }
}

// Local re-exports of types used in signatures above to keep this file self-contained.
import { StatsChart, CategoryCount, StatusCount } from '../model/Types';

export const dataService: DataService = new DataService();

