// System-intent adapters for 平安扣 Pinankou.
// Headless-safe stubs: provide real want/intent where cheap, otherwise return a
// descriptive result without throwing. Photo capture is local-only per spec.

import { common } from '@kit.AbilityKit';
import { wantAgent, Want } from '@kit.AbilityKit';
import { hilog } from '@kit.PerformanceAnalysisKit';

const DOMAIN = 0x0910;

export interface DialResult {
  ok: boolean;
  message: string;
}

export class DialAdapter {
  // Attempts to hand off to the system dialer via action dial. Returns a result
  // the UI can surface as feedback; never throws.
  async startCall(context: common.Context | null, phone: string): Promise<DialResult> {
    const trimmed = phone.trim();
    if (trimmed.length === 0) {
      return { ok: false, message: '号码为空' } as DialResult;
    }
    if (!context) {
      return { ok: false, message: '暂不可拨打' } as DialResult;
    }
    try {
      const want: Want = {
        action: 'ohos.want.action.dial',
        uri: `tel:${trimmed}`,
      };
      const abilityCtx = context as common.UIAbilityContext;
      await abilityCtx.startAbility(want);
      return { ok: true, message: `正在呼叫 ${trimmed}` } as DialResult;
    } catch (err) {
      hilog.error(DOMAIN, 'pinankou.dial', 'dial failed: %{public}s', JSON.stringify(err));
      return { ok: false, message: '拨号不可用' } as DialResult;
    }
  }
}

export class PhotoAdapter {
  // Local-only evidence capture. Headless stub returns empty URI; visual layer
  // will wire camera/picker when design lands.
  async capture(_context: common.Context | null): Promise<string> {
    return '';
  }
}

export const dialAdapter: DialAdapter = new DialAdapter();
export const photoAdapter: PhotoAdapter = new PhotoAdapter();

// keep wantAgent import referenced for future deep-link needs without unused warnings
export const _wantAgentRef = wantAgent;

