// AppController — view-model / state machine for 平安扣 Pinankou.
// Headless-logic surface that maps ui-behavior.json events to DataService mutations.
// Framework-agnostic (no ArkUI decorators) so the visual layer can wrap it later.

import { common } from '@kit.AbilityKit';
import { dataService } from '../services/DataService';
import { dialAdapter } from '../services/SystemAdapters';
import { storage } from '../services/StorageService';
import {
  SafetyRecord,
  RiskHazard,
  Contact,
  RecordFilter,
  RiskFilter,
  TrackingFilter,
  StatsSnapshot,
  StatsRange,
  RecordCategory,
  FixStatus,
  SheetKind,
  HomeSummary,
  emptyRecordFilter,
  emptyRiskFilter,
  emptyTrackingFilter,
} from '../model/Types';

type Listener = () => void;

export interface Feedback {
  message: string;
  visible: boolean;
}

export class AppController {
  private context: common.Context | null = null;
  private listeners: Set<Listener> = new Set<Listener>();

  // root state
  ready: boolean = false;

  // navigation / shell
  sheet: SheetKind = 'none';
  filterTarget: 'records' | 'risks' = 'records';

  // form targets (id of item being edited, '' = create)
  editingRecordId: string = '';
  editingRiskId: string = '';
  editingContactId: string = '';
  checkpointNoteTargetId: string = '';

  // filter state
  recordFilter: RecordFilter = emptyRecordFilter();
  riskFilter: RiskFilter = emptyRiskFilter();
  trackingFilter: TrackingFilter = emptyTrackingFilter();

  // stats state
  statsRange: StatsRange = 'week';
  statsCategory: RecordCategory | 'all' = 'all';

  // form draft state
  recordDraft: SafetyRecord = this.blankRecordDraft();
  riskDraft: RiskHazard = this.blankRiskDraft();
  contactDraft: Contact = this.blankContactDraft();
  checkpointNoteDraft: string = '';

  // filter sheet draft
  filterStatusDraft: FixStatus[] = [];
  filterCategoryDraft: RecordCategory[] = [];

  // feedback / errors
  formError: string = '';
  feedback: Feedback = { message: '', visible: false } as Feedback;

  // ---- lifecycle ----
  async init(context: common.Context): Promise<void> {
    this.context = context;
    await storage.init(context);
    await dataService.loadAll();
    this.ready = true;
    this.emit();
  }

  subscribe(listener: Listener): () => void {
    this.listeners.add(listener);
    const unsub = storage.onChange(listener);
    return () => {
      this.listeners.delete(listener);
      unsub();
    };
  }

  private emit(): void {
    this.listeners.forEach((l: Listener) => {
      try {
        l();
      } catch (err) {
        // swallow listener errors so a bad observer can't break state propagation
      }
    });
  }

  // ---- derived getters (consumed by pages during visual integration) ----
  summary(): HomeSummary {
    return dataService.computeHomeSummary();
  }

  recordsView(): SafetyRecord[] {
    return dataService.getRecords(this.recordFilter);
  }

  risksView(): RiskHazard[] {
    return dataService.getRisks(this.riskFilter);
  }

  trackingView(): RiskHazard[] {
    return dataService.getTrackingItems(this.trackingFilter);
  }

  patrolSession() {
    return dataService.getPatrol();
  }

  contactsView(): Contact[] {
    return dataService.getContacts();
  }

  statsView(): StatsSnapshot {
    return dataService.computeStats(this.statsRange, this.statsCategory);
  }

  // ---- sheet / form events ----
  openAddRecordSheet(): void {
    this.editingRecordId = '';
    this.recordDraft = this.blankRecordDraft();
    this.formError = '';
    this.sheet = 'record-form';
    this.emit();
  }

  openEditRecord(id: string): void {
    const list = dataService.getRecords(emptyRecordFilter());
    const found = list.find((r: SafetyRecord) => r.id === id);
    if (found) {
      this.editingRecordId = id;
      this.recordDraft = {
        id: found.id,
        title: found.title,
        category: found.category,
        note: found.note,
        photoUri: found.photoUri,
        createdAt: found.createdAt,
        updatedAt: found.updatedAt,
      };
      this.formError = '';
      this.sheet = 'record-form';
      this.emit();
    }
  }

  openAddRiskSheet(): void {
    this.editingRiskId = '';
    this.riskDraft = this.blankRiskDraft();
    this.formError = '';
    this.sheet = 'risk-form';
    this.emit();
  }

  openEditRisk(id: string): void {
    const list = dataService.getRisks(emptyRiskFilter());
    const found = list.find((r: RiskHazard) => r.id === id);
    if (found) {
      this.editingRiskId = id;
      this.riskDraft = {
        id: found.id,
        title: found.title,
        location: found.location,
        severity: found.severity,
        description: found.description,
        photoUri: found.photoUri,
        fixStatus: found.fixStatus,
        dueAt: found.dueAt,
        createdAt: found.createdAt,
        updatedAt: found.updatedAt,
      };
      this.formError = '';
      this.sheet = 'risk-form';
      this.emit();
    }
  }

  openAddContactSheet(): void {
    this.editingContactId = '';
    this.contactDraft = this.blankContactDraft();
    this.formError = '';
    this.sheet = 'contact-form';
    this.emit();
  }

  openEditContact(id: string): void {
    const list = dataService.getContacts();
    const found = list.find((c: Contact) => c.id === id);
    if (found) {
      this.editingContactId = id;
      this.contactDraft = {
        id: found.id,
        name: found.name,
        role: found.role,
        phone: found.phone,
      };
      this.formError = '';
      this.sheet = 'contact-form';
      this.emit();
    }
  }

  openCheckpointNote(checkpointId: string): void {
    this.checkpointNoteTargetId = checkpointId;
    const session = dataService.getPatrol();
    let note = '';
    if (session && session.checkpoints) {
      const cp = session.checkpoints.find((c) => c.id === checkpointId);
      if (cp) {
        note = cp.note;
      }
    }
    this.checkpointNoteDraft = note;
    this.sheet = 'checkpoint-note';
    this.emit();
  }

  openFilterSheet(target: 'records' | 'risks'): void {
    this.filterTarget = target;
    if (target === 'records') {
      this.filterStatusDraft = this.recordFilter.statuses.slice();
      this.filterCategoryDraft = this.recordFilter.categories.slice();
    } else {
      this.filterStatusDraft = this.riskFilter.statuses.slice();
      this.filterCategoryDraft = [];
    }
    this.sheet = 'filter';
    this.emit();
  }

  closeSheet(): void {
    this.sheet = 'none';
    this.formError = '';
    this.emit();
  }

  // ---- draft mutators (bound to inputs) ----
  setRecordDraftField(field: 'title' | 'category' | 'note' | 'photoUri', value: string): void {
    if (field === 'title') {
      this.recordDraft.title = value;
    } else if (field === 'category') {
      this.recordDraft.category = value as RecordCategory;
    } else if (field === 'note') {
      this.recordDraft.note = value;
    } else if (field === 'photoUri') {
      this.recordDraft.photoUri = value;
    }
    this.emit();
  }

  setRiskDraftField(field: 'title' | 'location' | 'severity' | 'description' | 'photoUri', value: string): void {
    if (field === 'title') {
      this.riskDraft.title = value;
    } else if (field === 'location') {
      this.riskDraft.location = value;
    } else if (field === 'severity') {
      this.riskDraft.severity = value as RiskSeverityCast;
    } else if (field === 'description') {
      this.riskDraft.description = value;
    } else if (field === 'photoUri') {
      this.riskDraft.photoUri = value;
    }
    this.emit();
  }

  setContactDraftField(field: 'name' | 'role' | 'phone', value: string): void {
    if (field === 'name') {
      this.contactDraft.name = value;
    } else if (field === 'role') {
      this.contactDraft.role = value;
    } else if (field === 'phone') {
      this.contactDraft.phone = value;
    }
    this.emit();
  }

  setCheckpointNoteDraft(value: string): void {
    this.checkpointNoteDraft = value;
    this.emit();
  }

  toggleFilterStatusDraft(status: FixStatus): void {
    const idx = this.filterStatusDraft.indexOf(status);
    if (idx >= 0) {
      this.filterStatusDraft.splice(idx, 1);
    } else {
      this.filterStatusDraft.push(status);
    }
    this.emit();
  }

  toggleFilterCategoryDraft(category: RecordCategory): void {
    const idx = this.filterCategoryDraft.indexOf(category);
    if (idx >= 0) {
      this.filterCategoryDraft.splice(idx, 1);
    } else {
      this.filterCategoryDraft.push(category);
    }
    this.emit();
  }

  // ---- save / submit events ----
  saveRecord(): void {
    const title = this.recordDraft.title.trim();
    if (title.length === 0) {
      this.formError = '请填写标题';
      this.emit();
      return;
    }
    dataService.saveRecord({
      id: this.editingRecordId,
      title: title,
      category: this.recordDraft.category,
      note: this.recordDraft.note,
      photoUri: this.recordDraft.photoUri,
      createdAt: 0,
      updatedAt: 0,
    });
    this.flashFeedback(this.editingRecordId.length > 0 ? '记录已更新' : '记录已保存');
    this.closeSheet();
  }

  saveRisk(): void {
    const title = this.riskDraft.title.trim();
    if (title.length === 0) {
      this.formError = '请填写隐患标题';
      this.emit();
      return;
    }
    dataService.saveRisk({
      id: this.editingRiskId,
      title: title,
      location: this.riskDraft.location,
      severity: this.riskDraft.severity,
      description: this.riskDraft.description,
      photoUri: this.riskDraft.photoUri,
      fixStatus: 'pending',
      dueAt: this.riskDraft.dueAt,
      createdAt: 0,
      updatedAt: 0,
    });
    this.flashFeedback(this.editingRiskId.length > 0 ? '隐患已更新' : '隐患已上报');
    this.closeSheet();
  }

  saveContact(): void {
    const name = this.contactDraft.name.trim();
    const phone = this.contactDraft.phone.trim();
    if (name.length === 0) {
      this.formError = '请填写姓名';
      this.emit();
      return;
    }
    if (phone.length === 0) {
      this.formError = '请填写电话';
      this.emit();
      return;
    }
    dataService.saveContact({
      id: this.editingContactId,
      name: name,
      role: this.contactDraft.role,
      phone: phone,
    });
    this.flashFeedback(this.editingContactId.length > 0 ? '联系人已更新' : '联系人已添加');
    this.closeSheet();
  }

  saveCheckpointNote(): void {
    if (this.checkpointNoteTargetId.length === 0) {
      this.closeSheet();
      return;
    }
    dataService.saveCheckpointNote(this.checkpointNoteTargetId, this.checkpointNoteDraft);
    this.flashFeedback('备注已保存');
    this.closeSheet();
  }

  // ---- patrol events ----
  startPatrol(): void {
    dataService.startPatrol();
    this.flashFeedback('巡检已开始');
    this.emit();
  }

  endPatrol(): void {
    dataService.endPatrol();
    this.flashFeedback('巡检已结束');
    this.emit();
  }

  addCheckpoint(label?: string): void {
    dataService.addCheckpoint(label);
    this.emit();
  }

  toggleCheckpoint(checkpointId: string): void {
    dataService.toggleCheckpoint(checkpointId);
    this.emit();
  }

  // ---- contact actions ----
  async callContact(id: string): Promise<void> {
    const list = dataService.getContacts();
    const found = list.find((c: Contact) => c.id === id);
    if (!found) {
      return;
    }
    const result = await dialAdapter.startCall(this.context, found.phone);
    this.flashFeedback(result.message);
  }

  deleteContact(id: string): void {
    dataService.deleteContact(id);
    this.flashFeedback('联系人已删除');
    this.emit();
  }

  // ---- tracking events ----
  advanceFixStatus(id: string): void {
    dataService.advanceRisk(id);
    this.emit();
  }

  filterTrackingStatus(status: FixStatus): void {
    // toggle single-status filter
    if (this.trackingFilter.statuses.length === 1 && this.trackingFilter.statuses[0] === status) {
      this.trackingFilter = emptyTrackingFilter();
    } else {
      this.trackingFilter = { statuses: [status], onlyOverdue: false } as TrackingFilter;
    }
    this.emit();
  }

  // ---- filter apply / reset ----
  applyFilter(): void {
    if (this.filterTarget === 'records') {
      this.recordFilter = {
        query: this.recordFilter.query,
        statuses: this.filterStatusDraft.slice(),
        categories: this.filterCategoryDraft.slice(),
      };
    } else {
      this.riskFilter = {
        query: this.riskFilter.query,
        severities: this.riskFilter.severities,
        statuses: this.filterStatusDraft.slice(),
      };
    }
    this.closeSheet();
  }

  resetFilter(): void {
    if (this.filterTarget === 'records') {
      this.recordFilter = emptyRecordFilter();
    } else {
      this.riskFilter = emptyRiskFilter();
    }
    this.filterStatusDraft = [];
    this.filterCategoryDraft = [];
    this.closeSheet();
  }

  setRecordsQuery(query: string): void {
    this.recordFilter.query = query;
    this.emit();
  }

  setRisksQuery(query: string): void {
    this.riskFilter.query = query;
    this.emit();
  }

  // ---- stats events ----
  setStatsRange(range: StatsRange): void {
    this.statsRange = range;
    this.emit();
  }

  setStatsCategory(category: RecordCategory | 'all'): void {
    this.statsCategory = category;
    this.emit();
  }

  exportStats(): void {
    const snap = dataService.computeStats(this.statsRange, this.statsCategory);
    const line = `记录 ${snap.totalRecords} · 待整改隐患 ${snap.openRisks} · 本周闭环 ${snap.resolvedThisWeek} · 闭环率 ${snap.completionRate}%`;
    this.flashFeedback(`已生成本地统计：${line}`);
  }

  // ---- feedback helper ----
  private flashFeedback(message: string): void {
    this.feedback = { message: message, visible: true } as Feedback;
    this.emit();
  }

  dismissFeedback(): void {
    this.feedback = { message: '', visible: false } as Feedback;
    this.emit();
  }

  // ---- blank drafts ----
  private blankRecordDraft(): SafetyRecord {
    return {
      id: '',
      title: '',
      category: 'general',
      note: '',
      photoUri: '',
      createdAt: 0,
      updatedAt: 0,
    };
  }

  private blankRiskDraft(): RiskHazard {
    return {
      id: '',
      title: '',
      location: '',
      severity: 'medium',
      description: '',
      photoUri: '',
      fixStatus: 'pending',
      dueAt: 0,
      createdAt: 0,
      updatedAt: 0,
    };
  }

  private blankContactDraft(): Contact {
    return { id: '', name: '', role: '', phone: '' };
  }
}

