private bumpIdSeed(): void {
  const all: number[] = [];
  const collect = (id: string) => {
    const parts = id.split('_');
    const last = parts[parts.length - 1];
    const n = Number.parseInt(last, 10);
    if (!Number.isNaN(n)) {
      all.push(n);
    }
  };
  this.records.forEach((r: SafetyRecord) => collect(r.id));
  this.risks.forEach((r: RiskHazard) => collect(r.id));
  this.contacts.forEach((c: Contact) => collect(c.id));
  this.idCounter = all.length > 0 ? Math.max(...all) + 1 : 1;
}

